import React, { useEffect, useRef, useState } from "react";
import { useNavigate } from "react-router-dom";
import AOS from "aos";
import "aos/dist/aos.css";
import Cropper from "react-easy-crop";
import "./Home.css";
import logo1 from "../../assets/home-icon.png";

const getCroppedImg = async (imageSrc, crop, maxSize = 1024) => {
    const image = await createImage(imageSrc);
    const canvas = document.createElement("canvas");
    const ctx = canvas.getContext("2d");

    if (!ctx) return null;

    const safeX = Math.max(0, Math.floor(crop.x || 0));
    const safeY = Math.max(0, Math.floor(crop.y || 0));
    const safeWidth = Math.min(image.naturalWidth - safeX, Math.floor(crop.width || image.naturalWidth));
    const safeHeight = Math.min(image.naturalHeight - safeY, Math.floor(crop.height || image.naturalHeight));

    if (safeWidth <= 0 || safeHeight <= 0) return null;

    const scaleFactor = Math.min(1, maxSize / Math.max(safeWidth, safeHeight));
    const newWidth = Math.floor(safeWidth * scaleFactor);
    const newHeight = Math.floor(safeHeight * scaleFactor);

    canvas.width = newWidth;
    canvas.height = newHeight;

    ctx.drawImage(image, safeX, safeY, safeWidth, safeHeight, 0, 0, newWidth, newHeight);

    return new Promise((resolve, reject) => {
        canvas.toBlob(
            (blob) => {
                if (!blob) return reject(new Error("Erro ao converter a imagem."));
                const reader = new FileReader();
                reader.readAsDataURL(blob);
                reader.onloadend = () => resolve(reader.result);
                reader.onerror = reject;
            },
            "image/jpeg",
            0.7
        );
    });
};

const createImage = (url) =>
    new Promise((resolve, reject) => {
        const img = new Image();
        img.crossOrigin = "anonymous";
        img.src = url;
        img.onload = () => resolve(img);
        img.onerror = reject;
    });

function Home() {
    const navigate = useNavigate();
    const [showRegister, setShowRegister] = useState(false);
    const [name, setName] = useState("");
    const [surname, setSurname] = useState("");
    const [email, setEmail] = useState("");
    const [profilePic, setProfilePic] = useState(null);
    const [croppedImage, setCroppedImage] = useState(null);
    const logoDiv = useRef();

    useEffect(() => {
        AOS.init({ duration: 1000, once: true });
    }, []);

    const handleLogin = () => {
        const user = localStorage.getItem("user");
        if (user) navigate("/mapa");
        else alert("😕 Não encontramos seu cadastro. Que tal fazer um? 🎉");
    };

    const handleRegister = async () => {
        if (name && surname && email && croppedImage) {
            const user = { name, surname, email, profilePic: croppedImage, capiba: Math.floor(Math.random() * 201) };
            localStorage.setItem("user", JSON.stringify(user));
            navigate("/mapa");
        } else {
            alert("Preencha todos os campos antes de continuar.");
        }
    };

    const handleFileChange = async (event) => {
        const file = event.target.files[0];
        if (file) {
            const reader = new FileReader();
            reader.onloadend = async () => {
                setProfilePic(reader.result);
                const cropped = await getCroppedImg(reader.result, { x: 0, y: 0, width: 512, height: 512 });
                if (cropped) setCroppedImage(cropped);
            };
            reader.readAsDataURL(file);
        }
    };

    const handleClick = () => {
        logoDiv.current.style.display = 'none';
        setShowRegister(true);
    };

    return (
        <div className="home">
            <div className="content">
                <div className="logo" ref={logoDiv}>
                    <img src={logo1} alt="capivara" data-aos="zoom-in" />
                    <h1 data-aos="fade-right">Pule!</h1>
                    <span data-aos="fade-right">
                        Colete moedas capibas e ajude a transformar o carnaval do Recife.
                    </span>
                </div>

                {!showRegister ? (
                    <div className="logins">
                        <button onClick={handleClick} className="btns">Fazer meu cadastro</button>
                        <button onClick={handleLogin} className="guestBtn">Já tenho cadastro</button>
                    </div>
                ) : (
                    <div className="register">
                        <input type="text" placeholder="Nome" className="texts" value={name} onChange={(e) => setName(e.target.value)} />
                        <input type="text" placeholder="Sobrenome" className="texts" value={surname} onChange={(e) => setSurname(e.target.value)} />
                        <input type="email" placeholder="E-mail" className="texts" value={email} onChange={(e) => setEmail(e.target.value)} />

                        <label>Escolha sua foto de perfil:</label>
                        <input type="file" accept="image/*" className="imageImput" onChange={handleFileChange} />

                        {croppedImage && <img src={croppedImage} alt="Perfil" className="profile-preview" />}

                        <button onClick={handleRegister} className="btns">Ir para o app</button>
                    </div>
                )}
            </div>
        </div>
    );
}

export default Home;
